"""Records photos by HTTP Post/Get from Jibo's Media Service"""
import os
import json
import shutil
import threading
import time
try:
    from Tkinter import Label
except ImportError:
    from tkinter import Label
import requests


class PhotoRecorder(object):
    """PhotoRecorder Class"""

    def __init__(self, name, robot, output_dir, root, ui_queue):
        self.name = name
        self.__url = 'http://' + robot + ':8486/media/photo'
        self.__directory = output_dir + '/' + name
        self.__root = root
        self.__ui_queue = ui_queue
        self.__cancelled = False
        self.__running = False
        self.__thread = None

        # Create UI text label
        self.__label = Label(self.__root)
        self.__label.pack()

        # Create request data for START
        data = {}
        data["camera"] = 0
        data["width"] = 1280
        data["height"] = 720
        data["type"] = 2
        data = json.dumps(data)
        self.__data_start = data

    def start(self):
        """Create main thread"""
        self.update_ui('Starting recorder')

        # Remove previous directory and make new directory
        shutil.rmtree(self.__directory, ignore_errors=True)
        os.makedirs(self.__directory)

        # Create thread
        self.__running = True
        self.__thread = threading.Thread(target=self.run)
        self.__thread.start()

    def run(self):
        """Run thread; HTTP Post/Get photo data"""
        while not self.__cancelled:
            if self.__running:
                # POST start request
                post_response = self.post_message()
                if post_response is not None and post_response.ok:
                    # Grab UUID from response
                    uuid = post_response.json()["id"]
                    url_uuid = self.__url  + '?id=' + uuid
                    # GET photo request
                    get_response = requests.get(url_uuid, stream=True)
                    # If response is good, then write to file else post error to UI
                    if get_response.ok:
                        # Get timestamp in milliseconds
                        timestamp = int(round(time.time() * 1000))
                        # Setup file path
                        filename = 'frame-{:d}.jpg'.format(timestamp)
                        path = os.path.join(self.__directory, filename)
                        # Write raw to file
                        try:
                            with open(path, 'wb') as datafile:
                                shutil.copyfileobj(get_response.raw, datafile)
                        except IOError as err:
                            self.update_ui(
                                "I/O error({0}): {1}".format(err.errno, err.strerror), 'red')
                        # Update UI
                        self.update_ui(str(timestamp), 'dark green', False)
                    else:
                        self.update_ui('Could not get the photo', 'red')

    def post_message(self):
        """HTTP post a message"""
        try:
            post_response = requests.post(self.__url, self.__data_start)
            return post_response
        except requests.exceptions.ConnectionError:
            self.update_ui('Error: cannot http post to robot', 'red')
        # Didn't get a response
        self.__running = False
        return None

    def update_ui(self, message, color='blue', printout=True):
        """Update GUI and print to termintal"""
        text = '[' + self.name + '] '+ message
        if printout:
            print(text)
        self.__ui_queue.insert(0, {"label":self.__label, "text":text, "color":color})

    def stop(self):
        """Pausing thread"""
        if self.__running:
            self.__running = False
            # Wait to let thread process the stop, then update UI
            time.sleep(0.5)
            self.update_ui('Stopping recorder', 'dark green')
        else:
            self.update_ui('Never started', 'red')

    def exit(self):
        """Exit thread"""
        self.update_ui('Exiting recorder')
        self.__running = False
        self.__cancelled = True
        if self.__thread is not None:
            self.__thread.join()
